-- ============================================================
-- Step 1-2/6: UPSERT medsec_products (筆 1001 ~ 2000)
-- 共 1000 筆
-- 邏輯：用 ON CONFLICT(id) DO UPDATE，所以
--   - 已存在的 id → 更新所有欄位
--   - 不存在的 id → 新增
-- ============================================================


ON CONFLICT (id) DO UPDATE SET
  name=EXCLUDED.name, specification=EXCLUDED.specification, catalog_number=EXCLUDED.catalog_number, uom=EXCLUDED.uom, stock_qty=EXCLUDED.stock_qty, unit_cost=EXCLUDED.unit_cost, manufacturer_code=EXCLUDED.manufacturer_code, product_series=EXCLUDED.product_series, fee_type_code=EXCLUDED.fee_type_code, fee_type=EXCLUDED.fee_type, dms_category_code=EXCLUDED.dms_category_code, dms_category=EXCLUDED.dms_category, dms_subcategory_code=EXCLUDED.dms_subcategory_code, dms_subcategory=EXCLUDED.dms_subcategory, warehouse_code=EXCLUDED.warehouse_code, warehouse_name=EXCLUDED.warehouse_name, description=EXCLUDED.description, supplier_code=EXCLUDED.supplier_code, supplier_name=EXCLUDED.supplier_name, last_cost_orig=EXCLUDED.last_cost_orig, last_cost_twd=EXCLUDED.last_cost_twd, material_cost=EXCLUDED.material_cost, standard_cost=EXCLUDED.standard_cost;
